672	func (optr *Operator) getTrustedBundle(proxy *configv1.Proxy) ([]byte, error) {
673		var trustBundle []byte
674		certPool := x509.NewCertPool()
675		// this is the generic trusted bundle for things like self-signed registries.
676		additionalTrustBundle, err := optr.getCAsFromConfigMap(ctrlcommon.OpenshiftConfigNamespace, "user-ca-bundle", "ca-bundle.crt")
677		if err != nil && !apierrors.IsNotFound(err) {
678			return nil, err
679		}
680		if len(additionalTrustBundle) > 0 {
681			if !certPool.AppendCertsFromPEM(additionalTrustBundle) {
682				return nil, fmt.Errorf("configmap %s/%s doesn't have a valid PEM bundle", ctrlcommon.OpenshiftConfigNamespace, "user-ca-bundle")
683			}
684			trustBundle = append(trustBundle, additionalTrustBundle...)
685		}
686	
687		// this is the trusted bundle specific for proxy things and can differ from the generic one above.
688		if proxy != nil && proxy.Spec.TrustedCA.Name != "" && proxy.Spec.TrustedCA.Name != "user-ca-bundle" {
689			proxyTrustBundle, err := optr.getCAsFromConfigMap(ctrlcommon.OpenshiftConfigNamespace, proxy.Spec.TrustedCA.Name, "ca-bundle.crt")
690			if err != nil {
691				return nil, err
692			}
693			if len(proxyTrustBundle) > 0 {
694				if !certPool.AppendCertsFromPEM(proxyTrustBundle) {
695					return nil, fmt.Errorf("configmap %s/%s doesn't have a valid PEM bundle", ctrlcommon.OpenshiftConfigNamespace, proxy.Spec.TrustedCA.Name)
696				}
697				trustBundle = append(trustBundle, proxyTrustBundle...)
698			}
699		}
700		return trustBundle, nil
