448	// Merges the cluster's default node disruption policies with the user defined policies, if any.
449	func MergeClusterPolicies(userDefinedClusterPolicies opv1.NodeDisruptionPolicyConfig) opv1.NodeDisruptionPolicyClusterStatus {
450	
451		mergedClusterPolicies := opv1.NodeDisruptionPolicyClusterStatus{}
452	
453		// Add default file policies to the merged list.
454		mergedClusterPolicies.Files = append(mergedClusterPolicies.Files, defaultClusterPolicies.Files...)
455	
456		// Iterate through user file policies.
457		// If there is a conflict with default policy, replace that entry in the merged list with the user defined policy.
458		// If there was no conflict, add the user defined policy as a new entry to the merged list.
459		for _, userDefinedPolicyFile := range userDefinedClusterPolicies.Files {
460			override := false
461			for i, defaultPolicyFile := range defaultClusterPolicies.Files {
462				if defaultPolicyFile.Path == userDefinedPolicyFile.Path {
463					mergedClusterPolicies.Files[i] = convertSpecFileToStatusFile(userDefinedPolicyFile)
464					override = true
465					break
466				}
467			}
468			if !override {
469				mergedClusterPolicies.Files = append(mergedClusterPolicies.Files, convertSpecFileToStatusFile(userDefinedPolicyFile))
470			}
471		}
472	
473		// Add default service unit policies to the merged list.
474		mergedClusterPolicies.Units = append(mergedClusterPolicies.Units, defaultClusterPolicies.Units...)
475	
476		// Iterate through user service unit policies.
477		// If there is a conflict with default policy, replace that entry in the merged list with the user defined policy.
478		// If there was no conflict, add the user defined policy as a new entry to the merged list.
479		for _, userDefinedPolicyUnit := range userDefinedClusterPolicies.Units {
480			override := false
481			for i, defaultPolicyUnit := range defaultClusterPolicies.Units {
482				if defaultPolicyUnit.Name == userDefinedPolicyUnit.Name {
483					mergedClusterPolicies.Units[i] = convertSpecUnitToStatusUnit(userDefinedPolicyUnit)
484					override = true
485					break
486				}
487			}
488			if !override {
489				mergedClusterPolicies.Units = append(mergedClusterPolicies.Units, convertSpecUnitToStatusUnit(userDefinedPolicyUnit))
490			}
491		}
492	
493		// If no user defined SSH policy exists, use the cluster defaults.
494		if len(userDefinedClusterPolicies.SSHKey.Actions) == 0 {
495			mergedClusterPolicies.SSHKey = *defaultClusterPolicies.SSHKey.DeepCopy()
496		} else {
497			mergedClusterPolicies.SSHKey = convertSpecSSHKeyToStatusSSHKey(*userDefinedClusterPolicies.SSHKey.DeepCopy())
498		}
499		return mergedClusterPolicies
500	}
