750	func (dn *Daemon) calculatePostConfigChangeNodeDisruptionAction(diff *machineConfigDiff, diffFileSet, diffUnitSet []string) ([]opv1.NodeDisruptionPolicyStatusAction, error) {
751	
752		var mcop *opv1.MachineConfiguration
753		var pollErr error
754		// Wait for mcop.Status.NodeDisruptionPolicyStatus to populate, otherwise error out. This shouldn't take very long
755		// as this is done by the operator sync loop, but may be extended if transitioning to TechPreview as the operator restarts,
756		if err := wait.PollUntilContextTimeout(context.TODO(), 5*time.Second, 2*time.Minute, true, func(_ context.Context) (bool, error) {
757			mcop, pollErr = dn.mcopClient.OperatorV1().MachineConfigurations().Get(context.TODO(), ctrlcommon.MCOOperatorKnobsObjectName, metav1.GetOptions{})
758			if pollErr != nil {
759				klog.Errorf("calculating NodeDisruptionPolicies: MachineConfiguration/cluster has not been created yet")
760				pollErr = fmt.Errorf("MachineConfiguration/cluster has not been created yet")
761				return false, nil
762			}
763	
764			// Ensure status.ObservedGeneration matches the last generation of MachineConfiguration
765			if mcop.Generation != mcop.Status.ObservedGeneration {
766				klog.Errorf("calculating NodeDisruptionPolicies: NodeDisruptionPolicyStatus is not up to date.")
767				pollErr = fmt.Errorf("NodeDisruptionPolicyStatus is not up to date")
768				return false, nil
769			}
770			return true, nil
771		}); err != nil {
772			klog.Errorf("NodeDisruptionPolicyStatus was not ready: %v", pollErr)
773			return nil, fmt.Errorf("NodeDisruptionPolicyStatus was not ready: %v", pollErr)
774		}
775	
776		// Continue policy calculation if no errors were encountered in fetching the policy.
777		// If a machine-config-daemon-force file is present, it means the user wants to
778		// move to desired state without additional validation. We will reboot the node in
779		// this case regardless of what MachineConfig diff is.
780		klog.Infof("Calculating node disruption actions")
781		if _, err := os.Stat(constants.MachineConfigDaemonForceFile); err == nil {
782			if err = os.Remove(constants.MachineConfigDaemonForceFile); err != nil {
783				return []opv1.NodeDisruptionPolicyStatusAction{}, fmt.Errorf("failed to remove force validation file: %w", err)
784			}
785			klog.Infof("Setting post config change node disruption action to Reboot; %s present", constants.MachineConfigDaemonForceFile)
786			return []opv1.NodeDisruptionPolicyStatusAction{{
787				Type: opv1.RebootStatusAction,
788			}}, nil
789		}
790	
791		if diff.osUpdate || diff.kargs || diff.fips || diff.kernelType || diff.extensions {
792			// must reboot
793			return []opv1.NodeDisruptionPolicyStatusAction{{
794				Type: opv1.RebootStatusAction,
795			}}, nil
796		}
797		if !diff.files && !diff.units && !diff.passwd {
798			// This is a diff which requires no actions
799			klog.Infof("No changes in files, units or SSH keys, no NodeDisruptionPolicies are in effect")
800			return []opv1.NodeDisruptionPolicyStatusAction{{
801				Type: opv1.NoneStatusAction,
802			}}, nil
803		}
804	
805		// Calculate actions based on file, unit and ssh diffs
806		nodeDisruptionActions := calculatePostConfigChangeNodeDisruptionActionFromMCDiffs(diff.passwd, diffFileSet, diffUnitSet, mcop.Status.NodeDisruptionPolicyStatus.ClusterPolicies)
807	
808		// Print out node disruption actions for debug purposes
809		klog.Infof("Calculated node disruption actions:")
810		for _, action := range nodeDisruptionActions {
811			switch action.Type {
812			case opv1.ReloadStatusAction:
813				klog.Infof("%v - %v", action.Type, action.Reload.ServiceName)
814			case opv1.RestartStatusAction:
815				klog.Infof("%v - %v", action.Type, action.Restart.ServiceName)
816			default:
817				klog.Infof("%v", action.Type)
818			}
819		}
820	
821		return nodeDisruptionActions, nil
